class Solution:
    def countFancy(self, l, r):
        # independent construction: brute-force check every integer in the (narrow) range
        # directly against the definitions, with no shared helper functions or precomputed
        # sets from the optimal solution.
        def is_monotone(x):
            digits = [int(c) for c in str(x)]
            if len(digits) == 1:
                return True
            inc = all(digits[i] < digits[i+1] for i in range(len(digits) - 1))
            dec = all(digits[i] > digits[i+1] for i in range(len(digits) - 1))
            return inc or dec
        def digit_sum(x):
            return sum(int(c) for c in str(x))
        count = 0
        for x in range(l, r + 1):
            if is_monotone(x) or is_monotone(digit_sum(x)):
                count += 1
        return count

