from itertools import combinations
from functools import lru_cache

def _build_good_set():
    good = set(range(10))
    for size in range(2, 10):
        for combo in combinations(range(1, 10), size):
            good.add(int(''.join(map(str, combo))))
    for size in range(2, 11):
        for combo in combinations(range(0, 10), size):
            good.add(int(''.join(map(str, sorted(combo, reverse=True)))))
    return good

_GOOD = sorted(_build_good_set())
_GOOD_SUMS = set(v for v in _GOOD if v <= 144)

class Solution:
    def countFancy(self, l, r):
        import bisect

        def count_good_in_range(lo, hi):
            a = bisect.bisect_left(_GOOD, lo)
            b = bisect.bisect_right(_GOOD, hi)
            return b - a

        def count_digitsum_upto(n):
            if n < 0:
                return 0
            digits = list(map(int, str(n)))
            length = len(digits)

            @lru_cache(maxsize=None)
            def rec(pos, tight, s):
                if pos == length:
                    return 1 if s in _GOOD_SUMS else 0
                limit = digits[pos] if tight else 9
                total = 0
                for d in range(0, limit + 1):
                    total += rec(pos + 1, tight and d == limit, s + d)
                return total

            result = rec(0, True, 0)
            rec.cache_clear()
            return result

        def count_both_in_range(lo, hi):
            a = bisect.bisect_left(_GOOD, lo)
            b = bisect.bisect_right(_GOOD, hi)
            return sum(1 for x in _GOOD[a:b] if sum(int(c) for c in str(x)) in _GOOD_SUMS)

        good_count = count_good_in_range(l, r)
        sum_count = count_digitsum_upto(r) - count_digitsum_upto(l - 1)
        both_count = count_both_in_range(l, r)
        return good_count + sum_count - both_count

